<!DOCTYPE html>
<html>
<head>
    <meta charset="utf-8">
    <title>Tracking - {{ $user?->first_name . ' ' . $user?->last_name }}</title>
    <meta name="viewport" content="width=device-width, initial-scale=1.0">

    <style>
        html, body { margin:0; height:100%; }
        #map { height:100%; }
        .tracking-card{
            position: fixed;
            bottom: 0;
            left: 50%;
            transform: translateX(-50%);
            width: 92vw;
            max-width: 460px;

            background: #fff;
            border-radius: 22px 22px 0 0;
            padding: 25px;
            box-shadow: 0 -10px 35px rgba(0,0,0,0.2);

            z-index: 9999;
            font-family: Arial, sans-serif;
        }

        .toggle-btn{
            position:absolute;
            top:0px;
            left:50%;
            transform:translateX(-50%);

            width:50px;
            height:20px;

            display:flex;
            align-items:center;
            justify-content:center;

            cursor:pointer;
        }

        .toggle-btn span{
            width:40px;
            height:4px;

            background:#d1d1d1;
            border-radius:10px;

            transition:all .2s ease;
        }

        .toggle-btn:hover span{
            background:#bcbcbc;
        }

        .info-box{
            display:flex;
            align-items:center;
            gap:12px;

            background:#f8f8f8;
            padding:12px;
            border-radius:14px;
            margin-bottom:10px;
        }

        .driver-vehicle-box{
            background:#f8f8f8;
            padding:12px;
            border-radius:14px;
        }

        .driver{
            background:transparent;
            padding:0;
            margin-bottom:10px;
        }

        .avatar{
            width:46px;
            height:46px;
            border-radius:12px;
            object-fit:cover;
        }

        .info-text h4{
            margin:0;
            font-size:16px;
            font-weight:600;
        }

        .vehicle-row{
            display:flex;
            justify-content:space-between;
            align-items:center;
        }

        .vehicle-info h4{
            margin:0;
            font-size:15px;
        }

        .vehicle-info p{
            margin:4px 0 0;
            color:#777;
            font-size:14px;
        }

        .vehicle-image-box{
            background:#eee;
            padding:8px;
            border-radius:10px;
        }

        .vehicle-image-box img{
            width:40px;
        }

        .trip-overlay{
            position:fixed;
            inset:0;

            display:none;
            justify-content:center;
            align-items:center;

            backdrop-filter:blur(6px);
            background:rgba(0,0,0,0.25);

            z-index:10000;
        }

        .trip-completed-card{

            background:white;
            padding:40px 55px;
            border-radius:20px;

            text-align:center;

            box-shadow:0 20px 60px rgba(0,0,0,0.25);

            animation:popup 0.35s ease;
        }

        .success-icon{

            width:70px;
            height:70px;

            border-radius:50%;
            background:#22c55e;

            color:white;
            font-size:36px;
            font-weight:bold;

            display:flex;
            align-items:center;
            justify-content:center;

            margin:auto;
            margin-bottom:18px;
        }

        .trip-completed-card h2{
            margin:0;
            font-size:26px;
        }

        .trip-completed-card p{
            margin-top:6px;
            color:#666;
            font-size:15px;
        }

        .mb-2 {
            margin-bottom: .5rem;
        }

        @keyframes popup{
            from{
                transform:scale(.8);
                opacity:0;
            }
            to{
                transform:scale(1);
                opacity:1;
            }
        }
    </style>
</head>

