    const tripInfo = @json($tripInfo);
    const VEHICLE_PATH = tripInfo?.vehicle_type === 'car' ? CAR_PATH : BIKE_PATH;
    const ANCHOR_POINT1 = tripInfo?.vehicle_type === 'car' ? 77 : 39;
    const ANCHOR_POINT2 = tripInfo?.vehicle_type === 'car' ? 20 : 20;

    function initMap(){
        let encodedPolyline = @json($polyline);
        let routePath =
            google.maps.geometry.encoding.decodePath(encodedPolyline);

        const pickUp = {
            lat: {{ $pickupPoint[0] }},
            lng: {{ $pickupPoint[1] }}
        }
        const driverLastLocation = {
            lat: {{ $driverLastLocation[0] }},
            lng: {{ $driverLastLocation[1] }}
        };
        const dropOff = {
            lat: {{ $destinationPoint[0] }},
            lng: {{ $destinationPoint[1] }}
        };
        let userPos = driverLastLocation;
        let map = new google.maps.Map(document.getElementById("map"), {
            zoom: 16,
            center: driverLastLocation,
            gestureHandling:"greedy",
            disableDoubleClickZoom: true,
            zoomControl: false,
            disableDefaultUI: true
        });
        const vehicleSymbol = {
            path: VEHICLE_PATH,
            fillColor: "#ffffff",
            fillOpacity: 1,
            strokeColor: "#000000",
            strokeWeight: 2,
            scale: 0.3,
            anchor: new google.maps.Point(ANCHOR_POINT1,ANCHOR_POINT2),
        };

        const userMarker = new google.maps.Marker({
            position: driverLastLocation,
            map,
            icon: vehicleSymbol
        });
        const destinationMarker = new google.maps.Marker({
            position: dropOff,
            map,
        });
        const routeLine = new google.maps.Polyline({
            path: routePath,
            strokeWeight: 5,
            map
        });
        if(routePath.length > 1){
            vehicleSymbol.rotation = google.maps.geometry.spherical.computeHeading(
                routePath[0],
                routePath[1]
            );
            userMarker.setIcon(vehicleSymbol);
        }

        let trackingInterval = setInterval(fetchTracking, 10000);

        function fetchTracking() {

            $.ajax({
                url: '{{ route('track.data', $token) }}',
                method: 'GET',
                success: function(response){
                    const data = response.data;

                    if(data.encoded_polyline && data.encoded_polyline !== encodedPolyline){
                        encodedPolyline = data.encoded_polyline;
                        routePath = google.maps.geometry.encoding.decodePath(encodedPolyline);
                        routeLine.setPath(routePath);
                    }

                    const lat = parseFloat(data.latitude);
                    const lng = parseFloat(data.longitude);

                    moveMarker(lat,lng);
                },
                error: function(xhr){
                    clearInterval(trackingInterval);
                    if (xhr.status == 409) {
                        document.getElementById("tripCompletedOverlay").style.display = "flex";

                        return;
                    }

                    if (xhr.status == 404) {
                        alert('Something went wrong! Please refresh the page.');
                        return;
                    }
                }
            });

        }

        function moveMarker(lat, lng){
            const pos = new google.maps.LatLng(lat, lng);

            const dist = google.maps.geometry.spherical.computeDistanceBetween(
                new google.maps.LatLng(userPos.lat, userPos.lng),
                pos
            );

            if(dist < 10){
                return;
            }

            const rotation = getClosestRouteHeading({lat,lng}, routePath);

            vehicleSymbol.rotation = rotation;
            userMarker.setIcon(vehicleSymbol);
            userMarker.setPosition(pos);

            if(!map.getBounds().contains(pos)){
                map.panTo(pos);
            }

            userPos = {lat,lng};
        }
        function getClosestRouteHeading(position, path) {
            let closestIndex = 0;
            let minDist = Infinity;

            path.forEach((p, i) => {
                const d = google.maps.geometry.spherical.computeDistanceBetween(
                    new google.maps.LatLng(position.lat, position.lng),
                    p
                );

                if (d < minDist) {
                    minDist = d;
                    closestIndex = i;
                }
            });

            const nextIndex = Math.min(closestIndex + 1, path.length - 1);

            return google.maps.geometry.spherical.computeHeading(
                path[closestIndex],
                path[nextIndex]
            );
        }

        window.addEventListener("beforeunload", function () {
            clearInterval(trackingInterval);
        });
    }
</script>
<script>
    function toggleCard() {
        const content = document.getElementById("cardContent");

        if(content.style.display === "none"){
            content.style.display = "block";
        }else{
            content.style.display = "none";
        }

    }
</script>
